proof_block:
// Uniqueness of insertion position into a strictly sorted sequence (k absent).
// This is provable from the requires alone (it only mentions the pre-state).
// In the ensures-proof context, the antecedent gives us
//   sorted(post1_self_@) = sorted(pre_self_@.insert(r1 as int, k))   and
//   sorted(post2_self_@) = sorted(pre_self_@.insert(r2 as int, k)),
// which fire this forall at p1=r1 as int, p2=r2 as int, yielding r1==r2.
// Then Seq congruence collapses post1_self_@ and post2_self_@ to the same
// Seq::insert call, so det_insert_equal holds.
assert forall |p1: int, p2: int|
    #![trigger pre_self_@.insert(p1, k), pre_self_@.insert(p2, k)]
    0 <= p1 && p1 <= pre_self_@.len() &&
    0 <= p2 && p2 <= pre_self_@.len() &&
    sorted(pre_self_@.insert(p1, k)) &&
    sorted(pre_self_@.insert(p2, k))
    implies p1 == p2 by {
    K::cmp_properties();
    if p1 < p2 {
        // In s1 = pre.insert(p1, k): s1[p1] = k, s1[p1+1] = pre[p1].
        // sorted(s1) at p1, p1+1 gives k < pre[p1].
        assert(pre_self_@.insert(p1, k)[p1] == k);
        assert(pre_self_@.insert(p1, k)[p1 + 1] == pre_self_@[p1]);
        assert(pre_self_@.insert(p1, k)[p1]
            .cmp_spec(pre_self_@.insert(p1, k)[p1 + 1]).lt());
        // In s2 = pre.insert(p2, k): since p1 < p2, s2[p1] = pre[p1]; s2[p2] = k.
        // sorted(s2) at p1, p2 gives pre[p1] < k.
        assert(pre_self_@.insert(p2, k)[p1] == pre_self_@[p1]);
        assert(pre_self_@.insert(p2, k)[p2] == k);
        assert(pre_self_@.insert(p2, k)[p1]
            .cmp_spec(pre_self_@.insert(p2, k)[p2]).lt());
        // Now k.cmp(pre[p1]).lt() and pre[p1].cmp(k).lt(); asymmetry from
        // cmp_properties makes Ordering both Less and Greater — contradiction.
    } else if p2 < p1 {
        // Symmetric.
        assert(pre_self_@.insert(p2, k)[p2] == k);
        assert(pre_self_@.insert(p2, k)[p2 + 1] == pre_self_@[p2]);
        assert(pre_self_@.insert(p2, k)[p2]
            .cmp_spec(pre_self_@.insert(p2, k)[p2 + 1]).lt());
        assert(pre_self_@.insert(p1, k)[p2] == pre_self_@[p2]);
        assert(pre_self_@.insert(p1, k)[p1] == k);
        assert(pre_self_@.insert(p1, k)[p2]
            .cmp_spec(pre_self_@.insert(p1, k)[p1]).lt());
    }
}
